// Resolve the three Anthropic family members from the registry.
// Preference order:
//   1. Seat 2 (Son) — canonical Anthropic seat. Its api_model_id is Opus primary;
//      its alternatives array contains sonnet + haiku fallbacks.
//   2. Gabriel synthesizer — also Anthropic, used as a cross-check.
//   3. Hardcoded defaults — only if registry fetch failed.

const DEFAULTS = {
  opus_model:   'claude-opus-4-7',
  sonnet_model: 'claude-sonnet-4-6',
  haiku_model:  'claude-haiku-4-5-20251001'
};

function pickByPrefix(alts, prefix) {
  if (!Array.isArray(alts)) return null;
  const ranked = alts.slice().sort(function (a, b) {
    return (a.rank || 99) - (b.rank || 99);
  });
  for (const alt of ranked) {
    if (alt && typeof alt.model === 'string' && alt.model.startsWith(prefix)) {
      return alt.model;
    }
  }
  return null;
}

let registry = null;
try {
  registry = $input.first().json;
} catch (e) {
  registry = null;
}

let opus = null;
let sonnet = null;
let haiku = null;
let registry_version = null;
let registry_updated = null;
let source = 'defaults';

if (registry && Array.isArray(registry.seats)) {
  const seat2 = registry.seats.find(function (s) { return s.seat_id === 2; });
  const gabriel = registry.gabriel || null;
  const alts = (seat2 && seat2.alternatives) || (gabriel && gabriel.alternatives) || [];

  opus   = (seat2 && seat2.api_model_id && seat2.api_model_id.startsWith('claude-opus-'))
            ? seat2.api_model_id
            : pickByPrefix(alts, 'claude-opus-');
  sonnet = pickByPrefix(alts, 'claude-sonnet-');
  haiku  = pickByPrefix(alts, 'claude-haiku-');

  registry_version = registry.version || null;
  registry_updated = registry.last_updated || null;
  source = 'registry';
}

const resolved = {
  opus_model:   opus   || DEFAULTS.opus_model,
  sonnet_model: sonnet || DEFAULTS.sonnet_model,
  haiku_model:  haiku  || DEFAULTS.haiku_model
};

return [{
  json: {
    opus_model:       resolved.opus_model,
    sonnet_model:     resolved.sonnet_model,
    haiku_model:      resolved.haiku_model,
    registry_version: registry_version,
    registry_updated: registry_updated,
    source:           source,
    task:             $('Set Task').first().json.task
  }
}];

// Parse the Director's JSON plan. The director is prefilled with '{' so the
// response content is a JSON object body (possibly without the opening brace).
// Fall back to a uniform plan if parsing fails for any reason.

const resolved = $('Resolve Models').first().json;
const originalTask = resolved.task;

function extractText(resp) {
  if (!resp) return '';
  if (resp.content && Array.isArray(resp.content) && resp.content[0] && resp.content[0].text) {
    return resp.content[0].text;
  }
  if (resp.error) return '';
  return '';
}

function stripFences(s) {
  return s.replace(/^\s*```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
}

function tryParsePlan(raw) {
  if (!raw) return null;
  const trimmed = stripFences(raw).trim();
  // The assistant was prefilled with '{' — if the response doesn't start with '{',
  // re-attach it so JSON.parse has a valid object.
  const candidate = trimmed.startsWith('{') ? trimmed : ('{' + trimmed);
  try {
    const parsed = JSON.parse(candidate);
    if (parsed && typeof parsed === 'object') return parsed;
  } catch (e) {
    // Last-ditch: find the first balanced {...} block.
    const m = candidate.match(/\{[\s\S]*\}/);
    if (m) {
      try { return JSON.parse(m[0]); } catch (e2) { return null; }
    }
  }
  return null;
}

const directorResp = $input.first().json;
const raw = extractText(directorResp);
const plan = tryParsePlan(raw);

const fallback = {
  opus_prompt:   'Provide a deep, carefully reasoned answer to the following task. Cover non-obvious risks and trade-offs.\n\nTask: ' + originalTask,
  sonnet_prompt: 'Provide a balanced, well-structured answer to the following task. Aim for clarity and completeness.\n\nTask: ' + originalTask,
  haiku_prompt:  'Provide a concise, concrete answer to the following task. Keep it short and actionable.\n\nTask: ' + originalTask
};

const used = (plan && plan.opus_prompt && plan.sonnet_prompt && plan.haiku_prompt) ? plan : fallback;
const planSource = (plan && plan.opus_prompt && plan.sonnet_prompt && plan.haiku_prompt) ? 'director' : 'fallback';

return [{
  json: {
    task:          originalTask,
    opus_prompt:   used.opus_prompt,
    sonnet_prompt: used.sonnet_prompt,
    haiku_prompt:  used.haiku_prompt,
    opus_model:    resolved.opus_model,
    sonnet_model:  resolved.sonnet_model,
    haiku_model:   resolved.haiku_model,
    plan_source:   planSource,
    director_raw:  raw
  }
}];

// Build the synthesis prompt from whichever members responded.
// continueOnFail means any subset of the three may have succeeded.

const plan = $('Parse Director Plan').first().json;
const task = plan.task;

function extractText(json) {
  if (!json) return '[No response]';
  if (json.content && Array.isArray(json.content) && json.content[0] && json.content[0].text) {
    return json.content[0].text;
  }
  if (json.error) {
    return '[Error: ' + JSON.stringify(json.error).substring(0, 300) + ']';
  }
  return '[No response]';
}

const labels = [
  { key: 'opus',   name: 'Opus',   role: 'Depth \u2014 reasoning and judgment' },
  { key: 'sonnet', name: 'Sonnet', role: 'Balance \u2014 general-purpose analysis' },
  { key: 'haiku',  name: 'Haiku',  role: 'Speed \u2014 concise action' }
];

const items = $input.all();
const sections = items.map(function (item, i) {
  const label = labels[i] || { name: 'Member ' + (i + 1), role: '' };
  const text = extractText(item.json);
  return '## ' + label.name + ' \u2014 ' + label.role + '\n' + text;
});

const synthesisPrompt =
  'You are Opus in the synthesis seat \u2014 speaking for the whole Anthropic Trinity.\n\n' +
  'Original task:\n"' + task + '"\n\n' +
  'Here are the three family members\u2019 parallel responses:\n\n' +
  sections.join('\n\n---\n\n') +
  '\n\nProduce a single unified answer. Explicitly note: (1) where the members agree, (2) where they meaningfully disagree and which view is strongest and why, (3) any gap none of them addressed. End with a direct final recommendation.';

return [{
  json: {
    task:              task,
    synthesis_prompt:  synthesisPrompt,
    member_responses:  sections,
    response_count:    sections.length,
    opus_model:        plan.opus_model,
    sonnet_model:      plan.sonnet_model,
    haiku_model:       plan.haiku_model,
    plan_source:       plan.plan_source
  }
}];
